import { N8nExecution } from 'n8n-workflow';

function detectRecursiveLoop(executions: N8nExecution[]): boolean {
  const nodeExecCounts = new Map<string, number>();

  for (const exec of executions) {
    for (const node of exec.nodes) {
      const count = (nodeExecCounts.get(node.id) || 0) + 1;
      nodeExecCounts.set(node.id, count);

      // Flag if same node executed >5 times consecutively
      if (count > 5 && node.data.input === node.data.output) {
        return true;
      }
    }
  }
  return false;
}

const SECRET_PATTERNS = [
  /(?i)(api[-_]?key|token|secret|password)[\s:=]+['"][^'"]{20,}/,
  /sk[-_][a-zA-Z0-9]{40,}/,
  /ak[-_][a-zA-Z0-9]{30,}/
];

function scanCredentialExposure(nodeData: any): string[] {
  const leaks: string[] = [];

  function scanObject(obj: any) {
    if (typeof obj === 'string') {
      for (const pattern of SECRET_PATTERNS) {
        const match = obj.match(pattern);
        if (match) {
          leaks.push(match[0].replace(/./g, '*'));
        }
      }
    } else if (obj && typeof obj === 'object') {
      Object.values(obj).forEach(scanObject);
    }
  }

  scanObject(nodeData);
  return leaks;
}

function detectStaleMemory(memoryNode: any, workflowStart: Date): boolean {
  const memoryItems = memoryNode.data?.messages || [];
  const ttlHours = 24;

  for (const item of memoryItems) {
    const itemAge = (new Date().getTime() - new Date(item.timestamp).getTime()) / (1000 * 60 * 60);

    if (itemAge > ttlHours) {
      console.warn(`Stale memory detected: ${itemAge.toFixed(1)}h old`);
      return true;
    }
  }

  return false;
}

