// Schema validation for expected AI output
const isValid = aiOutput && 
  typeof aiOutput.action === 'string' &&
  typeof aiOutput.parameters === 'object' &&
  aiOutput.parameters !== null;

if (!isValid) {
  throw new Error(`Invalid AI output: ${JSON.stringify(aiOutput)}`);
}

return {
  json: {
    validated: true,
    ...aiOutput
  }
};

function sanitizeToolParams(params: any): any {
  const cleanParams = { ...params };

  // Mask known credential fields
  const credentialFields = ['apiKey', 'token', 'password', 'secret'];

  function sanitize(obj: any): any {
    if (typeof obj === 'string' && credentialFields.some(field => obj.includes(field))) {
      return '[REDACTED]';
    }
    if (Array.isArray(obj)) {
      return obj.map(sanitize);
    }
    if (obj && typeof obj === 'object') {
      const sanitized: any = {};
      for (const [key, value] of Object.entries(obj)) {
        sanitized[key] = sanitize(value);
      }
      return sanitized;
    }
    return obj;
  }

  return sanitize(cleanParams);
}

return {
  json: sanitize($input.first()?.json)
};

